import React, { useEffect, useState } from 'react';

export default function Books() {
  const [books, setBooks] = useState([]);

  useEffect(() => {
    fetch('http://localhost:5000/api/book')
      .then(res => res.json())
      .then(data => setBooks(data));
  }, []);

  return <div>{books.length} books found</div>;
}
